/// Naming conventions derived from a dialect name (e.g. `"sqlite"`).
///
/// Provides consistent symbol names, header file names, and Rust type names
/// for a given dialect.
#[derive(Debug, Clone)]
pub struct DialectNaming {
    name: String,
}

impl DialectNaming {
    /// Create a new `DialectNaming` for the given dialect name.
    pub fn new(name: impl Into<String>) -> Self {
        Self { name: name.into() }
    }

    /// The raw dialect name (e.g. `"sqlite"`).
    #[must_use]
    pub fn name(&self) -> &str {
        &self.name
    }

    /// Include directory name (e.g. `"syntaqlite_sqlite"`).
    #[must_use]
    pub fn include_dir_name(&self) -> String {
        format!("syntaqlite_{}", self.name)
    }

    /// AST node header file name (e.g. `"sqlite_node.h"`).
    #[must_use]
    pub fn node_header_name(&self) -> String {
        format!("{}_node.h", self.name)
    }

    /// Dialect header file name (e.g. `"sqlite.h"`).
    #[must_use]
    pub fn dialect_header_name(&self) -> String {
        format!("{}.h", self.name)
    }

    /// Dialect dispatch header file name (e.g. `"sqlite_dialect_dispatch.h"`).
    #[must_use]
    pub fn dialect_dispatch_header_name(&self) -> String {
        format!("{}_dialect_dispatch.h", self.name)
    }

    /// C symbol name for the dialect function (e.g. `"syntaqlite_sqlite_dialect"`).
    #[must_use]
    pub fn dialect_symbol_fn_name(&self) -> String {
        format!("syntaqlite_{}_dialect", self.name)
    }

    /// C symbol name for the grammar function (e.g. `"syntaqlite_sqlite_grammar"`).
    #[must_use]
    pub fn grammar_fn_name(&self) -> String {
        format!("syntaqlite_{}_grammar", self.name)
    }

    /// Rust grammar struct type name (`"Grammar"`).
    #[must_use]
    pub fn grammar_struct_type(&self) -> String {
        "Grammar".to_owned()
    }

    /// Rust token enum type name (`"TokenType"`).
    #[must_use]
    pub fn token_type_name(&self) -> String {
        "TokenType".to_string()
    }

    /// Lemon parser symbol prefix (e.g. `"SynqSqliteParse"`).
    #[must_use]
    pub fn parser_symbol_prefix(&self) -> String {
        format!("Synq{}Parse", util::pascal_case(&self.name))
    }

    /// File name for the dialect-specific token constants header.
    /// E.g. `sqlite_tokens.h` for the `sqlite` dialect.
    #[must_use]
    pub fn tokens_header_name(&self) -> String {
        format!("{}_tokens.h", self.name)
    }

    /// Wrap `parse_h` content in a dialect-specific include guard.
    #[must_use]
    pub fn guarded_tokens_header(&self, parse_h: &str) -> String {
        let guard = format!(
            "SYNTAQLITE_{}_TOKENS_H",
            self.name.to_uppercase().replace('-', "_")
        );
        format!("#ifndef {guard}\n#define {guard}\n{parse_h}#endif /* {guard} */\n")
    }
}

/// Generated Rust source files for a dialect crate.
pub(crate) struct RustCodegenArtifacts {
    /// Rust token constants (`tokens.rs`).
    pub tokens_rs: String,
    /// Rust FFI node definitions (`ffi.rs`).
    pub ffi_rs: String,
    /// Rust AST node types (`ast.rs`).
    pub ast_rs: String,
    /// Grammar module (`grammar.rs`).
    pub grammar_rs: Option<String>,
    /// Dialect accessor module (`dialect.rs`).
    pub dialect_rs: Option<String>,
    /// Crate root module (`lib.rs`).
    pub lib_rs: String,
    /// Build script (`build.rs`).
    pub build_rs: String,
    /// Cargo manifest (`Cargo.toml`).
    pub cargo_toml: String,
    /// Functions catalog (`functions_catalog.rs`).
    pub functions_catalog_rs: Option<String>,
}

/// All generated C and Rust artifacts produced by the codegen pipeline.
pub(crate) struct CodegenArtifacts {
    /// Lemon-generated `parse.h` token defines.
    pub parse_h: String,
    /// Parser API header (`sqlite_parse.h`).
    pub parse_api_h: String,
    /// Lemon-generated `parse.c` parser implementation.
    pub parse_c: String,
    /// Tokenizer C source (`sqlite_tokenize.c`).
    pub tokenize_c: String,
    /// Keyword hash C source (`sqlite_keyword.c`).
    pub keyword_c: String,
    /// Tokenizer header (`sqlite_tokenize.h`).
    pub tokenize_h: String,
    /// Keyword header (`sqlite_keyword.h`).
    pub keyword_h: String,
    /// AST node definitions header (`*_node.h`).
    pub ast_nodes_h: String,
    /// AST builder header (`dialect_builder.h`).
    pub ast_builder_h: String,
    /// Dialect field metadata header (`dialect_meta.h`).
    pub dialect_meta_h: String,
    /// Dialect formatter tables header (`dialect_fmt.h`).
    pub dialect_fmt_h: String,
    /// Dialect token categories header (`dialect_tokens.h`).
    pub dialect_tokens_h: String,
    /// Dialect glue C source (`dialect.c`).
    pub dialect_c: String,
    /// Dialect public header (`*.h`).
    pub dialect_h: String,
    /// Dialect dispatch header (`*_dialect_dispatch.h`).
    pub dialect_dispatch_h: String,
    /// Minimal runtime tokens header containing only the tokens needed by
    /// `token_wrapped.c` in the grammar-agnostic engine crate.
    pub runtime_tokens_h: String,
    /// `SQLite` cflag index constants header (`cflags.h`).
    pub cflags_h: String,
    /// Semantic role byte array header (`dialect_roles.h`).
    pub dialect_roles_h: String,
    /// Generated Rust sources, when `include_rust` was set.
    pub rust: Option<RustCodegenArtifacts>,
}

/// Parse `#define SYNTAQLITE_TK_NAME VALUE` lines from lemon's parse.h output.
/// Returns structured `(name, value)` pairs where name is the short name (e.g. "ABORT").
/// Normalize a raw `SQLite` token name for use as a Rust enum variant.
///
/// `SQLite`'s grammar uses compound token names without underscores (e.g.
/// `ISNULL`, `NOTNULL`). Inserting underscores here lets `pascal_case`
/// produce proper `PascalCase` variants (`IsNull`, `NotNull`) downstream.
fn normalize_token_name(name: &str) -> String {
    match name {
        "ISNULL" => "IS_NULL".to_string(),
        "NOTNULL" => "NOT_NULL".to_string(),
        "ISNOT" => "IS_NOT".to_string(),
        "TRUEFALSE" => "TRUE_FALSE".to_string(),
        "COLUMNKW" => "COLUMN_KW".to_string(),
        other => other.to_string(),
    }
}

pub(crate) fn extract_token_defines(parse_h: &str) -> Vec<(String, u32)> {
    let mut tokens = Vec::new();
    for line in parse_h.lines() {
        let line = line.trim();
        if let Some(rest) = line.strip_prefix("#define SYNTAQLITE_TK_") {
            let mut parts = rest.split_whitespace();
            if let (Some(name), Some(value_str)) = (parts.next(), parts.next())
                && let Ok(value) = value_str.parse::<u32>()
            {
                tokens.push((normalize_token_name(name), value));
            }
        }
    }
    tokens
}

/// Token names needed by the grammar-agnostic runtime (`token_wrapped.c`).
const RUNTIME_TOKEN_NAMES: &[&str] = &[
    "PTR", "MINUS", "QNUMBER", "FLOAT", "INTEGER", "SPACE", "SEMI", "COMMENT",
];

/// Generate a minimal tokens header containing only the runtime-required tokens.
pub(crate) fn generate_runtime_tokens_header(token_defines: &[(String, u32)]) -> String {
    use crate::util::c_writer::CWriter;

    let mut w = CWriter::new();
    w.file_header();
    w.header_guard_start("SYNTAQLITE_TOKENS_H");
    w.newline();
    for (name, value) in token_defines {
        if RUNTIME_TOKEN_NAMES.contains(&name.as_str()) {
            w.line(&format!("#define SYNTAQLITE_TK_{name} {value}"));
        }
    }
    w.newline();
    w.header_guard_end("SYNTAQLITE_TOKENS_H");
    w.finish()
}

pub(crate) struct TokenizerExtractResult {
    pub(crate) char_map: String,
    pub(crate) upper_to_lower: String,
}

/// Parameters for a full codegen run.
pub(crate) struct CodegenRequest<'a> {
    /// Dialect naming conventions.
    pub dialect: &'a DialectNaming,
    /// Lemon grammar `.y` files as `(filename, content)` pairs.
    pub y_files: &'a [(String, String)],
    /// AST definition `.synq` files as `(filename, content)` pairs.
    pub synq_files: &'a [(String, String)],
    /// Additional keywords from extension grammars.
    pub extra_keywords: &'a [String],
    /// Lemon parser symbol prefix (e.g. `"SynqSqliteParse"`).
    pub parser_symbol_prefix: Option<&'a str>,
    /// Whether to generate Rust source files alongside C.
    pub include_rust: bool,
    /// Crate name for `Cargo.toml` (e.g. `"syntaqlite"`, `"syntaqlite-libsql"`).
    /// Only used when `include_rust` is true.
    pub crate_name: Option<&'a str>,
    /// Base .synq files for extension builds. When present, base items get
    /// pinned tags and extension items get tags after the base range.
    /// When `None`, all items from `synq_files` are treated as base.
    pub base_synq_files: Option<&'a [(&'a str, &'a str)]>,
    /// When `true`, the generated `Node<'a>` enum gets an `Other { id, tag }`
    /// variant for unknown tags (dialect extension support). When `false`,
    /// unknown tags are unreachable.
    pub open_for_extension: bool,
    /// Include path prefixes for `dialect.c`. Defaults to `""` for both
    /// internal and public — suitable for external dialect crates where
    /// all headers live in a single output directory.
    pub dialect_c_includes: DialectCIncludes<'a>,
}

/// A prepared codegen job for an external or amalgamated dialect.
///
/// Captures the merged file inputs and pre-computes `extra_keywords` (terminal
/// symbols in extension `.y` files that aren't in the base grammar).
///
/// Call [`write_to`](DialectCodegenJob::write_to) with an
/// [`OutputLayout`](crate::output_resolver::OutputLayout) to run the full
/// pipeline and write all artifacts.
pub struct DialectCodegenJob<'a> {
    dialect: &'a DialectNaming,
    y_files: &'a [(String, String)],
    synq_files: &'a [(String, String)],
    extra_keywords: Vec<String>,
    base_synq_files: Option<&'a [(&'a str, &'a str)]>,
    include_rust: bool,
    open_for_extension: bool,
    crate_name: Option<String>,
}

impl<'a> DialectCodegenJob<'a> {
    /// Create a new job from merged (base + extension) file sets.
    ///
    /// `extra_keywords` are extracted automatically from extension `.y` files —
    /// those not present in [`base_y_files`](crate::base_files::base_y_files).
    #[must_use]
    pub fn new(
        dialect: &'a DialectNaming,
        y_files: &'a [(String, String)],
        synq_files: &'a [(String, String)],
    ) -> Self {
        let ext_y_contents: Vec<&str> = y_files
            .iter()
            .filter(|(name, _)| {
                !base_files::base_y_files()
                    .iter()
                    .any(|(base_name, _)| *base_name == name.as_str())
            })
            .map(|(_, content)| content.as_str())
            .collect();
        let extra_keywords = extract_terminals_from_y(&ext_y_contents);
        Self {
            dialect,
            y_files,
            synq_files,
            extra_keywords,
            base_synq_files: None,
            include_rust: false,
            open_for_extension: false,
            crate_name: None,
        }
    }

    /// Pin the base `.synq` files as a baseline for extension tag numbering.
    #[must_use]
    pub const fn with_base_synq(mut self, files: &'a [(&'a str, &'a str)]) -> Self {
        self.base_synq_files = Some(files);
        self
    }

    /// Enable Rust codegen and set the crate name for `Cargo.toml`.
    #[must_use]
    pub fn with_rust(mut self, crate_name: &str) -> Self {
        self.include_rust = true;
        self.crate_name = Some(crate_name.to_string());
        self
    }

    /// Open the generated `Node` enum for dialect extension variants.
    #[must_use]
    pub fn open_for_extension(mut self) -> Self {
        self.open_for_extension = true;
        self
    }

    /// Run the full codegen pipeline and write all artifacts to `layout`.
    ///
    /// # Errors
    ///
    /// Returns an error if codegen or file I/O fails.
    pub fn write_to(
        &self,
        layout: &output_resolver::OutputLayout,
        ensure_dir: &impl Fn(&std::path::Path) -> Result<(), String>,
        write_file: &impl Fn(&std::path::Path, &str) -> Result<(), String>,
    ) -> Result<(), String> {
        let parser_prefix = self.dialect.parser_symbol_prefix();
        let request = CodegenRequest {
            dialect: self.dialect,
            y_files: self.y_files,
            synq_files: self.synq_files,
            extra_keywords: &self.extra_keywords,
            parser_symbol_prefix: Some(&parser_prefix),
            include_rust: self.include_rust,
            crate_name: self.crate_name.as_deref(),
            base_synq_files: self.base_synq_files,
            open_for_extension: self.open_for_extension,
            dialect_c_includes: layout.c_includes(),
        };
        let artifacts = generate_codegen_artifacts(&request)?;
        layout.write_codegen_artifacts(self.dialect, artifacts, ensure_dir, write_file)
    }
}

/// Return the set of token names that are keywords in the base `SQLite` table.
pub(crate) fn base_keyword_token_names() -> std::collections::HashSet<String> {
    mkkeyword::base_keyword_token_names()
}

/// Extract terminal symbols (potential keywords) from extension `.y` grammar files.
pub(crate) fn extract_terminals_from_y(extension_y_contents: &[&str]) -> Vec<String> {
    use std::collections::HashSet;

    let mut terminals: HashSet<String> = HashSet::new();

    for content in extension_y_contents {
        let Ok(grammar) = util::grammar_parser::LemonGrammar::parse(content) else {
            continue;
        };

        for tok in &grammar.tokens {
            if is_keyword_like(tok.name) {
                terminals.insert(tok.name.to_string());
            }
        }

        for fb in &grammar.fallbacks {
            for tok in &fb.tokens {
                if is_keyword_like(tok) {
                    terminals.insert(tok.to_string());
                }
            }
        }

        for rule in &grammar.rules {
            for sym in &rule.rhs {
                if is_keyword_like(sym.name) && sym.name != "ID" {
                    terminals.insert(sym.name.to_string());
                }
            }
        }
    }

    terminals.into_iter().collect()
}

fn is_keyword_like(name: &str) -> bool {
    name.len() >= 2 && name.chars().all(|c| c.is_ascii_uppercase())
}

fn parse_synq_items(
    synq_files: &[(String, String)],
) -> Result<Vec<util::synq_parser::Item>, String> {
    let mut all_items = Vec::new();
    for (name, content) in synq_files {
        let items =
            util::synq_parser::parse_synq_file(content).map_err(|e| format!("{name}: {e}"))?;
        all_items.extend(items);
    }
    Ok(all_items)
}

/// Run the full codegen pipeline and return all generated artifacts.
///
/// # Errors
///
/// Returns an error if grammar parsing, parser generation, or AST codegen fails.
#[expect(clippy::too_many_lines)]
pub(crate) fn generate_codegen_artifacts(
    request: &CodegenRequest<'_>,
) -> Result<CodegenArtifacts, String> {
    let parser_name = request.parser_symbol_prefix.unwrap_or("SynqSqliteParse");

    let all_items = parse_synq_items(request.synq_files)?;

    // For extension builds, parse base and extension items separately.
    // Both vecs must outlive the AstModel, so declare them here.
    let base_items_owned: Vec<util::synq_parser::Item>;
    let ext_items_owned: Vec<util::synq_parser::Item>;

    let ast_model = if let Some(base_synq) = request.base_synq_files {
        let base_owned: Vec<(String, String)> = base_synq
            .iter()
            .map(|(n, c)| (n.to_string(), c.to_string()))
            .collect();
        base_items_owned = parse_synq_items(&base_owned)?;

        let base_names: std::collections::HashSet<&str> =
            base_synq.iter().map(|(n, _)| *n).collect();
        let ext_files: Vec<(String, String)> = request
            .synq_files
            .iter()
            .filter(|(n, _)| !base_names.contains(n.as_str()))
            .map(|(n, c)| (n.clone(), c.clone()))
            .collect();
        ext_items_owned = if ext_files.is_empty() {
            Vec::new()
        } else {
            parse_synq_items(&ext_files)?
        };

        dialect_codegen::AstModel::new_with_extensions(&base_items_owned, &ext_items_owned)
            .map_err(|e| format!("extension validation: {e}"))?
    } else {
        dialect_codegen::AstModel::new(&all_items)
    };

    // Substitute the dialect_builder.h include path placeholder.
    // _common.y uses @DIALECT_BUILDER_H@ so the correct path (which varies
    // by output layout) is injected here rather than being hardcoded in the
    // grammar source.
    let y_files_substituted: Vec<(String, String)>;
    let y_files_for_parser = if request
        .y_files
        .iter()
        .any(|(_, c)| c.contains("@DIALECT_BUILDER_H@"))
    {
        y_files_substituted = request
            .y_files
            .iter()
            .map(|(name, content)| {
                (
                    name.clone(),
                    content.replace(
                        "@DIALECT_BUILDER_H@",
                        request.dialect_c_includes.ast_builder_h,
                    ),
                )
            })
            .collect();
        &y_files_substituted[..]
    } else {
        request.y_files
    };

    let work_dir =
        tempfile::TempDir::new().map_err(|e| format!("Failed to create temp directory: {e}"))?;
    parser_pipeline::generate_parser_from_contents(
        y_files_for_parser,
        parser_name,
        work_dir.path().to_string_lossy().as_ref(),
        Some(request.dialect_c_includes.tokens_header),
    )?;
    let parse_h = fs::read_to_string(work_dir.path().join("parse.h"))
        .map_err(|e| format!("Failed to read parse.h: {e}"))?;
    let parse_c = fs::read_to_string(work_dir.path().join("parse.c"))
        .map_err(|e| format!("Failed to read parse.c: {e}"))?;

    // Assemble tokenizer and keyword hash from pre-extracted fragments.
    let fragments = sqlite_fragments::load();
    let (tokenize_c, extract_result) = tokenizer_assembly::assemble(
        &fragments,
        request.dialect.name(),
        &request.dialect_c_includes,
    );
    let keyword_c = keyword_hash::generate(
        &extract_result,
        &fragments,
        request.dialect.name(),
        request.extra_keywords,
        &request.dialect_c_includes,
    )?;
    let keyword_h = keyword_hash::generate_keyword_h();

    let ast_nodes_h = ast_model.generate_ast_nodes_header(request.dialect.name());
    let ast_builder_h = ast_model.generate_ast_builder_header(request.dialect.name());
    let dialect_meta_h = ast_model
        .generate_c_field_metadata(request.dialect.name())
        .map_err(|e: CMetaCodegenError| e.to_string())?;
    let dialect_fmt_h = ast_model
        .generate_c_fmt_tables(request.dialect.name())
        .map_err(|e: CFmtCodegenError| e.to_string())?;
    let token_defines = extract_token_defines(&parse_h);
    // Build keyword set from the base mkkeywordhash table + dialect extra keywords.
    let mut keyword_names = base_keyword_token_names();
    for kw in request.extra_keywords {
        keyword_names.insert(kw.to_uppercase());
    }
    let dialect_tokens_h = generate_token_categories_header(&token_defines, Some(&keyword_names));
    let parse_api_h = generate_parse_h(request.dialect.name());
    let tokenize_h = generate_tokenize_h(request.dialect.name());
    let dialect_c = generate_dialect_c(
        request.dialect.name(),
        Some(&token_defines),
        &request.dialect_c_includes,
    );
    let dialect_h = generate_dialect_h(request.dialect.name());
    let dialect_dispatch_h = generate_dialect_dispatch_h(request.dialect.name());

    let rust = if request.include_rust {
        // All generated Rust files import from `crate` directly (they live
        // inside syntaqlite-syntax/src/sqlite/).
        let grammar_type = format!("super::grammar::{}", request.dialect.grammar_struct_type());
        let rust_paths = RustAstPaths {
            crate_prefix: "crate",
            // ffi_path: dialect-specific FFI structs live in the sibling ffi module.
            ffi_path: "super::ffi",
            nodes_path: "crate::ast",
            grammar_type: &grammar_type,
        };
        Some(RustCodegenArtifacts {
            tokens_rs: generate_rust_tokens(&token_defines[..], &request.dialect.token_type_name()),
            ffi_rs: ast_model.generate_rust_ffi_nodes(&rust_paths),
            ast_rs: ast_model.generate_rust_ast(&rust_paths, request.open_for_extension),
            grammar_rs: Some(generate_grammar_module(
                &request.dialect.grammar_fn_name(),
                &request.dialect.grammar_struct_type(),
                ast_model.root_node_name(),
                &request.dialect.token_type_name(),
                "crate",
            )),
            dialect_rs: Some(generate_dialect_module(
                &request.dialect.dialect_symbol_fn_name(),
                &request.dialect.grammar_struct_type(),
                "crate",
            )),
            lib_rs: generate_rust_lib(
                &request.dialect.dialect_symbol_fn_name(),
                &request.dialect.grammar_struct_type(),
                ast_model.root_node_name(),
                &request.dialect.token_type_name(),
            ),
            build_rs: generate_rust_build_rs(request.dialect.name()),
            cargo_toml: generate_cargo_toml(
                request.crate_name.unwrap_or_else(|| request.dialect.name()),
            ),
            functions_catalog_rs: None,
        })
    } else {
        None
    };

    let runtime_tokens_h = generate_runtime_tokens_header(&token_defines);
    let cflags_h = crate::extract::generate_cflags_h("parser");
    let dialect_roles_h = generate_c_roles_h(&ast_model, request.dialect.name());

    Ok(CodegenArtifacts {
        parse_h,
        parse_api_h,
        parse_c,
        tokenize_c,
        keyword_c,
        tokenize_h,
        keyword_h,
        ast_nodes_h,
        ast_builder_h,
        dialect_meta_h,
        dialect_fmt_h,
        dialect_tokens_h,
        dialect_c,
        dialect_h,
        dialect_dispatch_h,
        runtime_tokens_h,
        cflags_h,
        dialect_roles_h,
        rust,
    })
}

/// Read all files with the given extension from a directory, returning `(filename, content)` pairs
/// sorted by filename.
///
/// # Errors
///
/// Returns an error if the path is not a directory or directory reading fails.
pub fn read_named_files_from_dir(dir: &str, ext: &str) -> Result<Vec<(String, String)>, String> {
    let dir_path = std::path::Path::new(dir);
    if !dir_path.is_dir() {
        return Err(format!("{dir} is not a directory"));
    }

    let mut files: Vec<(String, String)> = fs::read_dir(dir_path)
        .map_err(|e| format!("Failed to read directory {dir}: {e}"))?
        .filter_map(|entry| {
            let path = entry.ok()?.path();
            if path.extension()?.to_str()? == ext {
                let name = path.file_name()?.to_str()?.to_string();
                let content = fs::read_to_string(&path).ok()?;
                Some((name, content))
            } else {
                None
            }
        })
        .collect();
    files.sort_by(|a, b| a.0.cmp(&b.0));
    Ok(files)
}

#[cfg(test)]
mod tests {
    use std::collections::BTreeSet;

    #[test]
    fn extract_terminals_collects_rhs_tokens_but_excludes_id() {
        let y = r"
%token PERFETTO MACRO.
%fallback ID PERFETTO MODULE.
cmd ::= INCLUDE PERFETTO MODULE ID DOT ID.
cmd ::= CREATE PERFETTO MACRO ID LP RP AS ANY.
";
        let got: BTreeSet<String> = super::extract_terminals_from_y(&[y]).into_iter().collect();
        let want: BTreeSet<String> = [
            "ANY", "AS", "CREATE", "DOT", "INCLUDE", "LP", "MACRO", "MODULE", "PERFETTO", "RP",
        ]
        .into_iter()
        .map(str::to_string)
        .collect();
        assert_eq!(got, want);
        assert!(!got.contains("ID"));
    }
}
